import{c as t,Q as a,j as o,m as s}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"How do I create a custom plan?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/create-custom-plan.md","filePath":"guide/recipes/admin/create-custom-plan.md","lastUpdated":1779094756000}'),r={name:"guide/recipes/admin/create-custom-plan.md"};function i(n,e,l,c,d,u){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-create-a-custom-plan" tabindex="-1">How do I create a custom plan? <a class="header-anchor" href="#how-do-i-create-a-custom-plan" aria-label="Permalink to &quot;How do I create a custom plan?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Finance Admin</strong></p></div><p>A custom plan is a private plan attached to one customer — used when a customer needs pricing or limits that don&#39;t fit the published plans (Starter / Professional / Enterprise).</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Finance → Plans</strong>.</li><li>Click <strong>Create Custom Plan</strong>.</li><li>Pick the <strong>customer</strong> the plan attaches to. Custom plans aren&#39;t visible to other customers.</li><li>Fill in: <ul><li><strong>Name</strong> and <strong>description</strong>.</li><li><strong>Meter limits</strong> — set MAU, API Calls, Storage, and Workflows for this plan.</li><li><strong>Pricing</strong> — base fee + per-unit overages.</li><li><strong>Effective from</strong> date.</li></ul></li><li>Click <strong>Create</strong>.</li><li>From the customer&#39;s <strong>Customer Billing</strong> page, switch them onto the new plan.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The custom plan appears in the Plans list with a <strong>Custom</strong> badge and the bound customer. Billing for the next invoice cycle uses the new plan; existing invoices are unaffected.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./configure-customer-billing">How do I configure billing for a customer?</a></li><li><a href="./issue-credit">How do I issue a credit?</a></li></ul>',9)])])}const h=t(r,[["render",i]]);export{m as __pageData,h as default};
